//! Spec-compliance edge cases: XML Parsing & Value Interpretation
//!
//! These tests target behavioral edge cases in OOXML value parsing where the
//! spec's fine print differs from naive implementation.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CanonDoc, InlineNode, Mark, MarkValue, VerticalMerge};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/edge-cases";

// ── helpers ──────────────────────────────────────────────────────────────
fn first_text_node(p: &stemma::ParagraphNode) -> &stemma::TextNode {
    // Access segments directly to get a reference (all_inlines_owned returns owned values).
    for seg in &p.segments {
        for inline in &seg.inlines {
            if let InlineNode::Text(t) = inline {
                return t;
            }
        }
    }
    panic!(
        "paragraph should have at least one text node, got text: '{}'",
        common::paragraph_text(p)
    );
}

fn first_table(doc: &CanonDoc) -> &stemma::TableNode {
    doc.blocks
        .iter()
        .find_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t),
            _ => None,
        })
        .expect("document should contain at least one table")
}

// =========================================================================
// EC-02: ST_OnOff boolean value forms (ISO 29500-1 §22.9.2.7)
// =========================================================================
//
// Paragraph layout in fixture:
//  [0] "Bold bare element"      — <w:b/>           = bold ON
//  [1] "Bold val=1"             — <w:b w:val="1"/> = bold ON
//  [2] "Bold val=true"          — <w:b w:val="true"/> = bold ON
//  [3] "Bold val=on"            — <w:b w:val="on"/>   = bold ON
//  [4] "Bold val=0"             — <w:b w:val="0"/>    = bold OFF
//  [5] "Bold val=false"         — <w:b w:val="false"/>= bold OFF
//  [6] "Bold val=off"           — <w:b w:val="off"/>  = bold OFF
//  [7] "Bold absent (inherit)"  — no <w:b>            = inherit
//  [8] "Italic bare element"    — <w:i/>              = italic ON
//  [9] "Italic val=0"           — <w:i w:val="0"/>    = italic OFF
// [10] "Italic val=off"         — <w:i w:val="off"/>  = italic OFF
// [11] "Strike bare element"    — <w:strike/>         = strike ON
// [12] "Strike val=off"         — <w:strike w:val="off"/> = strike OFF

/// ISO 29500-1 §22.9.2.7: Bare `<w:b/>` (no val attribute) means bold ON.
#[test]
fn ec02_bold_bare_element_is_on() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "st-onoff-boolean-forms");
    let paras = common::all_paragraphs(&doc);
    let p = &paras[0];
    assert!(
        common::paragraph_text(p).contains("Bold bare element"),
        "paragraph 0 should be 'Bold bare element', got '{}'",
        common::paragraph_text(p)
    );
    let t = first_text_node(p);
    assert!(
        t.marks.contains(&Mark::Bold),
        "Bare <w:b/> should produce Mark::Bold. Marks: {:?}",
        t.marks
    );
}

/// ISO 29500-1 §22.9.2.7: `<w:b w:val="1"/>` means bold ON.
#[test]
fn ec02_bold_val_1_is_on() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "st-onoff-boolean-forms");
    let paras = common::all_paragraphs(&doc);
    let p = &paras[1];
    assert!(common::paragraph_text(p).contains("Bold val=1"));
    let t = first_text_node(p);
    assert!(
        t.marks.contains(&Mark::Bold),
        "<w:b w:val=\"1\"/> should produce Mark::Bold. Marks: {:?}",
        t.marks
    );
}

