/// ISO 29500-1 §22.9.2.7: `<w:b w:val="off"/>` means bold OFF.
///
/// This is a subtle edge case: "off" is a valid ST_OnOff false value per spec,
/// but many parsers only check for "0" and "false".
#[test]
fn ec02_bold_val_off_is_off() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "st-onoff-boolean-forms");
    let paras = common::all_paragraphs(&doc);
    let p = &paras[6];
    assert!(common::paragraph_text(p).contains("Bold val=off"));
    let t = first_text_node(p);
    assert!(
        !t.marks.contains(&Mark::Bold),
        "<w:b w:val=\"off\"/> should NOT produce Mark::Bold. \
         Per ISO 29500-1 §22.9.2.7, \"off\" is a valid false value for ST_OnOff. \
         Marks: {:?}",
        t.marks
    );
}

