// =========================================================================
// EC-10: firstLine vs hanging indent mutual exclusion (§17.3.1.12)
// =========================================================================
//
// Paragraph layout in fixture:
//  [0] "Only firstLine indent (720 twips = 0.5 inch)" — first_line = +720
//  [1] "Only hanging indent (360 twips)"              — first_line = -360
//  [2] "Both firstLine=720 and hanging=360"           — first_line = +720

/// ISO 29500-1 §17.3.1.12: Only firstLine present.
#[test]
fn ec10_only_firstline() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "firstline-vs-hanging");
    let paras = common::all_paragraphs(&doc);
    let p = &paras[0];
    assert!(common::paragraph_text(p).contains("Only firstLine"));
    let indent = p
        .indent
        .as_ref()
        .expect("paragraph with w:ind firstLine=720 should have indent");
    assert_eq!(
        indent.effective_first_line_twips,
        Some(720),
        "firstLine=720 should produce first_line=Some(720)"
    );
}

/// ISO 29500-1 §17.3.1.12: Only hanging present (stored as negative first_line).
#[test]
fn ec10_only_hanging() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "firstline-vs-hanging");
    let paras = common::all_paragraphs(&doc);
    let p = &paras[1];
    assert!(common::paragraph_text(p).contains("Only hanging"));
    let indent = p
        .indent
        .as_ref()
        .expect("paragraph with w:ind hanging=360 should have indent");
    assert_eq!(
        indent.effective_first_line_twips,
        Some(-360),
        "hanging=360 should produce first_line=Some(-360)"
    );
}

/// ISO 29500-1 §17.3.1.12: When both firstLine and hanging are present,
/// hanging wins and firstLine is ignored.
///
/// The spec states: "The firstLine and hanging attributes are mutually
/// exclusive, if both are specified, then the firstLine value is ignored."
#[test]
fn ec10_hanging_wins_over_firstline() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "firstline-vs-hanging");
    let paras = common::all_paragraphs(&doc);
    let p = &paras[2];
    assert!(common::paragraph_text(p).contains("Both firstLine=720 and hanging=360"));
    let indent = p
        .indent
        .as_ref()
        .expect("paragraph with both firstLine and hanging should have indent");
    assert_eq!(
        indent.effective_first_line_twips,
        Some(-360),
        "When both firstLine=720 and hanging=360 are present, hanging should win. \
         Per ISO 29500-1 §17.3.1.12: 'the firstLine value is ignored'. \
         Got first_line={:?}",
        indent.effective_first_line_twips
    );
}

// =========================================================================
// EC-15: vMerge absent value means "continue" (§17.4.84)
// =========================================================================
//
// Table layout in fixture (4 rows x 2 cols):
//  Row 0, Col 0: vMerge="restart" — Restart
//  Row 1, Col 0: <w:vMerge/>      — Continue (bare, no val)
//  Row 2, Col 0: vMerge="continue" — Continue (explicit)
//  Row 3, Col 0: no vMerge         — None

/// ISO 29500-1 §17.4.84: `<w:vMerge w:val="restart"/>` starts a new merge.
#[test]
fn ec15_vmerge_restart() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "vmerge-absent-value");
    let table = first_table(&doc);
    assert!(
        table.rows.len() >= 4,
        "table should have at least 4 rows, got {}",
        table.rows.len()
    );
    assert_eq!(
        table.rows[0].cells[0].v_merge,
        VerticalMerge::Restart,
        "Row 0, Col 0 with <w:vMerge w:val=\"restart\"/> should be VerticalMerge::Restart"
    );
}

/// ISO 29500-1 §17.4.84: Bare `<w:vMerge/>` (no val attribute) means Continue,
/// NOT Restart. This is the subtle edge case.
#[test]
fn ec15_vmerge_bare_is_continue() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "vmerge-absent-value");
    let table = first_table(&doc);
    assert_eq!(
        table.rows[1].cells[0].v_merge,
        VerticalMerge::Continue,
        "Row 1, Col 0 with bare <w:vMerge/> should be VerticalMerge::Continue. \
         A bare vMerge element without val attribute means \"continue\" (merge from above), \
         NOT \"restart\" (start new merge). Per ISO 29500-1 §17.4.84."
    );
}

/// ISO 29500-1 §17.4.84: `<w:vMerge w:val="continue"/>` is explicit Continue.
#[test]
fn ec15_vmerge_explicit_continue() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "vmerge-absent-value");
    let table = first_table(&doc);
    assert_eq!(
        table.rows[2].cells[0].v_merge,
        VerticalMerge::Continue,
        "Row 2, Col 0 with <w:vMerge w:val=\"continue\"/> should be VerticalMerge::Continue"
    );
}

/// ISO 29500-1 §17.4.84: No vMerge element means no merge (None).
#[test]
fn ec15_vmerge_absent_is_none() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "vmerge-absent-value");
    let table = first_table(&doc);
    assert_eq!(
        table.rows[3].cells[0].v_merge,
        VerticalMerge::None,
        "Row 3, Col 0 with no vMerge element should be VerticalMerge::None"
    );
}

// EC-24: delText vs t for deleted run content (§17.3.3.7)
//
// Tests removed: the import pipeline normalizes pre-existing tracked changes
// (accepts insertions, removes deletions) via `normalize_if_needed` before
// building the canonical model. This is by design — the canonical view
// represents the accepted state of the document. Testing tracked-change
// preservation through import+view is incompatible with this architecture.
//
// The fixture (del-text-variants) is retained for future use if a
// tracked-change-aware import path is added.
